#ifdef I3_DEBUG
// DLGąöŔüżˇĽ­ Ĺ¸ŔĚĆ˛ąŮżˇ __DATE__·Î ľňŔş łŻÂĄ¸¦ ş¸±â˝±°Ô şŻ°ć. 2012.03.06
char *g_preMacroDateToInt()
{	
	static char szNewDate[32];
	const char szMonthNames[] = "JanFebMarAprMayJunJulAugSepOctNovDec";
	char szMonth[8];
	INT32 i32Year;
	INT32 i32Day;
	INT32 i32Month;
	
	sscanf(__DATE__, "%s %d %d", szMonth, &i32Day, &i32Year);
	i32Month = (INT32)((strstr(szMonthNames, szMonth) - szMonthNames)/3 + 1);
	sprintf_s(szNewDate, 32, "%d/%02d/%02d", i32Year, i32Month, i32Day);
	
	return szNewDate;
}
#endif

