void g_MakeBasicItemDBIdx( T_ItemDBIdx& TItemDBIdx, T_ItemID TItemID )
{
	if( 0 == TItemID )
	{
		TItemDBIdx = 0;
		return;
	}

	if( TItemID > DEFAULT_PARTS_ITEM_ID_MIN )
	{	// ±âş» ĆÄĂ÷ 
		TItemDBIdx = MAKE_DEFAULT_EQUIP_DBIDX ( GET_ITEM_TYPE( TItemID ) );
		return;
	}


	// ¸Ç łˇ ŔÚ¸® 1şńĆ®¸¦ ŔĚżëÇĎż© »ýĽşµČ DBIdx ŔÎÁö¸¦ Č®ŔÎ ÇŃ ČÄ ˝˝·Ô, Item ¸¦ ąÍ˝ş ÇŐ´Ď´Ů.
	TItemDBIdx = MAKE_DEFAULT_ITEM_DBIDX( TItemID );

}

